378: void Filter::chargeUpstreamCode(uint64_t response_status_code,
379:                                 const Http::ResponseHeaderMap& response_headers,
380:                                 Upstream::HostDescriptionOptConstRef upstream_host, bool dropped) {
381:   // Passing the response_status_code explicitly is an optimization to avoid
382:   // multiple calls to slow Http::Utility::getResponseStatus.
383:   ASSERT(response_status_code == Http::Utility::getResponseStatus(response_headers));
384:   if (config_->emit_dynamic_stats_ && !callbacks_->streamInfo().healthCheck()) {
385:     const Http::HeaderEntry* upstream_canary_header = response_headers.EnvoyUpstreamCanary();
386:     const bool is_canary = (upstream_canary_header && upstream_canary_header->value() == "true") ||
387:                            (upstream_host ? upstream_host->canary() : false);
388:     const bool internal_request = Http::HeaderUtility::isEnvoyInternalRequest(*downstream_headers_);
389: 
390:     Stats::StatName upstream_zone = upstreamZone(upstream_host);
391:     Http::CodeStats::ResponseStatInfo info{
392:         config_->scope_,
393:         cluster_->statsScope(),
394:         config_->empty_stat_name_,
395:         response_status_code,
396:         internal_request,
397:         route_->virtualHost()->statName(),
398:         request_vcluster_ ? request_vcluster_->statName() : config_->empty_stat_name_,
399:         route_stats_context_.has_value() ? route_stats_context_->statName()
400:                                          : config_->empty_stat_name_,
401:         config_->zone_name_,
402:         upstream_zone,
403:         is_canary};
404: 
405:     Http::CodeStats& code_stats = httpContext().codeStats();
406:     code_stats.chargeResponseStat(info, exclude_http_code_stats_);
407: 
408:     if (alt_stat_prefix_ != nullptr) {
409:       Http::CodeStats::ResponseStatInfo alt_info{config_->scope_,
410:                                                  cluster_->statsScope(),
411:                                                  alt_stat_prefix_->statName(),
412:                                                  response_status_code,
413:                                                  internal_request,
414:                                                  config_->empty_stat_name_,
415:                                                  config_->empty_stat_name_,
416:                                                  config_->empty_stat_name_,
417:                                                  config_->zone_name_,
418:                                                  upstream_zone,
419:                                                  is_canary};
420:       code_stats.chargeResponseStat(alt_info, exclude_http_code_stats_);
421:     }
422: 
423:     if (dropped) {
424:       cluster_->loadReportStats().upstream_rq_dropped_.inc();
425:     }
426:     if (upstream_host && Http::CodeUtility::is5xx(response_status_code)) {
427:       upstream_host->stats().rq_error_.inc();
428:     }
