440: Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
441:   downstream_headers_ = &headers;
442: 
443:   // Initialize the `modify_headers_` function that will be used to modify the response headers for
444:   // all upstream responses or local responses.
445:   modify_headers_ = [this](Http::ResponseHeaderMap& headers) {
446:     if (route_entry_ == nullptr) {
447:       return;
448:     }
449: 
450:     if (modify_headers_from_upstream_lb_) {
451:       modify_headers_from_upstream_lb_(headers);
452:     }
453: 
454:     if (attempt_count_ == 0 || !route_entry_->includeAttemptCountInResponse()) {
455:       return;
456:     }
457:     // This header is added without checking for config_->suppress_envoy_headers_ to mirror what
458:     // is done for upstream requests.
459:     headers.setEnvoyAttemptCount(attempt_count_);
460:   };
461: 
462:   // TODO: Maybe add a filter API for this.
463:   grpc_request_ = Grpc::Common::isGrpcRequestHeaders(headers);
464:   exclude_http_code_stats_ = grpc_request_ && config_->suppress_grpc_request_failure_code_stats_;
465: 
466:   // Only increment rq total stat if we actually decode headers here. This does not count requests
467:   // that get handled by earlier filters.
468:   stats_.rq_total_.inc();
469: 
470:   // Determine if there is a route entry or a direct response for the request.
471:   route_ = callbacks_->route();
472:   if (!route_) {
473:     stats_.no_route_.inc();
474:     ENVOY_STREAM_LOG(debug, "no route match for URL '{}'", *callbacks_, headers.getPathValue());
475: 
476:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::NoRouteFound);
477:     callbacks_->sendLocalReply(Http::Code::NotFound, "", nullptr, absl::nullopt,
478:                                StreamInfo::ResponseCodeDetails::get().RouteNotFound);
479:     return Http::FilterHeadersStatus::StopIteration;
480:   }
