957: void ClusterManagerImpl::updateClusterCounts() {
958:   // This if/else block implements a control flow mechanism that can be used by an ADS
959:   // implementation to properly sequence CDS and RDS updates. It is not enforcing on ADS. ADS can
960:   // use it to detect when a previously sent cluster becomes warm before sending routes that depend
961:   // on it. This can improve incidence of HTTP 503 responses from Envoy when a route is used before
962:   // it's supporting cluster is ready.
963:   //
964:   // We achieve that by leaving CDS in the paused state as long as there is at least
965:   // one cluster in the warming state. This prevents CDS ACK from being sent to ADS.
966:   // Once cluster is warmed up, CDS is resumed, and ACK is sent to ADS, providing a
967:   // signal to ADS to proceed with RDS updates.
968:   // If we're in the middle of shutting down (ads_mux_ already gone) then this is irrelevant.
969:   const bool all_clusters_initialized =
970:       init_helper_.state() == ClusterManagerInitHelper::State::AllClustersInitialized;
971:   if (all_clusters_initialized && xds_manager_.adsMux()) {
972:     const auto type_url = Config::getTypeUrl<envoy::config::cluster::v3::Cluster>();
973:     if (resume_cds_ == nullptr && !warming_clusters_.empty()) {
974:       resume_cds_ = xds_manager_.pause(type_url);
975:     } else if (warming_clusters_.empty()) {
976:       resume_cds_.reset();
977:     }
978:   }
979:   cm_stats_.active_clusters_.set(active_clusters_.size());
980:   cm_stats_.warming_clusters_.set(warming_clusters_.size());
981: }
