994: void ClusterManagerImpl::maybePreconnect(
995:     ThreadLocalClusterManagerImpl::ClusterEntry& cluster_entry,
996:     const ClusterConnectivityState& state,
997:     std::function<ConnectionPool::Instance*()> pick_preconnect_pool) {
998:   auto peekahead_ratio = cluster_entry.info()->peekaheadRatio();
999:   if (peekahead_ratio <= 1.0) {
1000:     return;
1001:   }
1002: 
1003:   // 3 here is arbitrary. Just as in ConnPoolImplBase::tryCreateNewConnections
1004:   // we want to limit the work which can be done on any given preconnect attempt.
1005:   for (int i = 0; i < 3; ++i) {
1006:     // See if adding this one new connection
1007:     // would put the cluster over desired capacity. If so, stop preconnecting.
1008:     //
1009:     // We anticipate the incoming stream here, because maybePreconnect is called
1010:     // before a new stream is established.
1011:     if (!ConnectionPool::ConnPoolImplBase::shouldConnect(
1012:             state.pending_streams_, state.active_streams_,
1013:             state.connecting_and_connected_stream_capacity_, peekahead_ratio, true)) {
1014:       return;
1015:     }
1016:     ConnectionPool::Instance* preconnect_pool = pick_preconnect_pool();
1017:     if (!preconnect_pool || !preconnect_pool->maybePreconnect(peekahead_ratio)) {
1018:       // Given that the next preconnect pick may be entirely different, we could
1019:       // opt to try again even if the first preconnect fails. Err on the side of
1020:       // caution and wait for the next attempt.
1021:       return;
1022:     }
1023:   }
1024: }
