463: void ConnectionManagerImpl::handleCodecErrorImpl(absl::string_view error, absl::string_view details,
464:                                                  StreamInfo::CoreResponseFlag response_flag) {
465:   ENVOY_CONN_LOG(debug, "dispatch error: {}", read_callbacks_->connection(), error);
466:   read_callbacks_->connection().streamInfo().setResponseFlag(response_flag);
467: 
468:   // HTTP/1.1 codec has already sent a 400 response if possible. HTTP/2 codec has already sent
469:   // GOAWAY.
470:   doConnectionClose(Network::ConnectionCloseType::FlushWriteAndDelay, response_flag, details);
471: }
